scwin.f_BeforePopUpEd = function (nmObj, cdObj, gubun1, pWinCloseTF) {
    var	cdObjVal = cdObj.getValue().trim() ;
    if (cdObjVal	== "") {
        nmObj.setValue("");
    } else {
        nmObj.setValue("");
        scwin.f_PopUp(gubun1, pWinCloseTF);
    }
}

